root.sql:
SELECT sc_mem_m_ucf_member_group.member_group_no, sc_mem_m_ucf_member_group.member_group_name, count( sc_cls_confirm_mem.membership_no ) as c_amount FROM sc_cls_confirm_mem, sc_mem_m_ucf_member_group ,sc_mem_m_membership_registered ,sc_mem_m_ucf_member_type ,sc_cls_confirm_data WHERE ( sc_cls_confirm_mem.member_group_no = sc_mem_m_ucf_member_group.member_group_no ) and ( ( sc_cls_confirm_mem.member_status_code = '0' ) ) and sc_mem_m_membership_registered.membership_no= sc_cls_confirm_mem.membership_no and sc_mem_m_ucf_member_type.mem_type_code = sc_cls_confirm_mem.mem_type
and sc_cls_confirm_data.confirm_date = sc_cls_confirm_mem.confirm_date and sc_cls_confirm_data.membership_no = sc_cls_confirm_mem.membership_no and sc_cls_confirm_data.data_group = 'SHR' and sc_cls_confirm_data.data_balance > 0
/*WHERE*/ --and sc_cls_confirm_mem.confirm_date = '31/1/2022' GROUP BY sc_mem_m_ucf_member_group.member_group_no, sc_mem_m_ucf_member_group.member_group_name order by sc_mem_m_ucf_member_group.member_group_no
